<?php
declare(strict_types=1);namespace App\Repositories\ControlEscaneres\Pdo;use App\Repositories\ControlEscaneres\Contracts\ScannerMovementRepositoryInterface;use App\DTO\ControlEscaneres\ScannerMovementCreateData;use App\Domain\ControlEscaneres\{ScannerMovement,ScannerFolio,MovementStatus};
final class PdoScannerMovementRepository extends AbstractPdoRepository implements ScannerMovementRepositoryInterface{private function map(array$r):ScannerMovement{return new ScannerMovement((int)$r['id'],(int)$r['scanner_id'],new ScannerFolio($r['folio']),new MovementStatus($r['estado']),$r['persona_entrega_nombre'],$r['numero_empleado'],$r['area_id']===null?null:(int)$r['area_id'],$r['turno'],$this->date($r['entregado_at']),$this->date($r['recibido_at']),$this->date($r['vence_at']),$r['entrega_registrada_por']===null?null:(int)$r['entrega_registrada_por'],$r['recepcion_registrada_por']===null?null:(int)$r['recepcion_registrada_por'],$r['devolucion_recibida_por_nombre'],$r['duracion_segundos']===null?null:(int)$r['duracion_segundos'],$r['observaciones'],$r['cancelado_por']===null?null:(int)$r['cancelado_por'],$this->date($r['cancelado_at']),$r['motivo_cancelacion'],$this->date($r['created_at']),$this->date($r['updated_at']));}private function one(string$q,array$p):?ScannerMovement{$r=$this->stmt($q,$p)->fetch(\PDO::FETCH_ASSOC);return is_array($r)?$this->map($r):null;}private function many(string$q,array$p=[]):array{return array_map(fn($r)=>$this->map($r),$this->stmt($q,$p)->fetchAll(\PDO::FETCH_ASSOC));}public function findById(int$id):?ScannerMovement{return$this->one('SELECT * FROM scanner_movimientos WHERE id=:id',['id'=>$id]);}public function findOpenByScannerId(int$id):?ScannerMovement{return$this->one("SELECT * FROM scanner_movimientos WHERE scanner_id=:id AND estado='abierto'",['id'=>$id]);}public function hasOpenMovement(int$id):bool{return$this->findOpenByScannerId($id)!==null;}public function create(ScannerMovementCreateData$d):ScannerMovement{$this->stmt("INSERT INTO scanner_movimientos(scanner_id,folio,estado,persona_entrega_nombre,numero_empleado,turno,entregado_at,entrega_registrada_por)VALUES(:s,:f,'abierto',:p,:e,:t,:a,:u)",['s'=>$d->scannerId,'f'=>$d->folio->value,'p'=>$d->personName,'e'=>$d->employeeNumber,'t'=>$d->shift,'a'=>$d->deliveredAt->format('Y-m-d H:i:s.u'),'u'=>$d->actor->userId]);return$this->findById((int)$this->pdo->lastInsertId());}public function closeAsReturned(int$id,\DateTimeImmutable$a,int$u,string$r,int$duration):void{$this->stmt("UPDATE scanner_movimientos SET estado='devuelto',recibido_at=:a,recepcion_registrada_por=:u,devolucion_recibida_por_nombre=:r,duracion_segundos=:d WHERE id=:id",['id'=>$id,'u'=>$u,'r'=>$r,'d'=>$duration,'a'=>$a->format('Y-m-d H:i:s.u')]);}public function cancel(int$id,int$u,string$r):void{$this->stmt("UPDATE scanner_movimientos SET estado='cancelado',cancelado_por=:u,motivo_cancelacion=:r,cancelado_at=CURRENT_TIMESTAMP WHERE id=:id",compact('id','u','r'));}public function markOverdue(\DateTimeImmutable$a):int{$s=$this->stmt("UPDATE scanner_movimientos SET estado='vencido' WHERE estado='abierto' AND vence_at<:a",['a'=>$a->format('Y-m-d H:i:s.u')]);return$s->rowCount();}public function listByScannerId(int$id):array{return$this->many('SELECT * FROM scanner_movimientos WHERE scanner_id=:id',['id'=>$id]);}public function listOpen():array{return$this->many("SELECT * FROM scanner_movimientos WHERE estado='abierto'");}public function listByDateRange(\DateTimeImmutable$f,\DateTimeImmutable$t):array{return$this->many('SELECT * FROM scanner_movimientos WHERE entregado_at BETWEEN :f AND :t',['f'=>$f->format('Y-m-d H:i:s.u'),'t'=>$t->format('Y-m-d H:i:s.u')]);}public function listByActor(int$id):array{return$this->many('SELECT * FROM scanner_movimientos WHERE entrega_registrada_por=:id OR recepcion_registrada_por=:id',['id'=>$id]);}public function listByArea(int$id):array{return$this->many('SELECT * FROM scanner_movimientos WHERE area_id=:id',['id'=>$id]);}public function countOpen():int{return(int)$this->stmt("SELECT COUNT(*) FROM scanner_movimientos WHERE estado='abierto'")->fetchColumn();}public function countOverdue(\DateTimeImmutable$a):int{return(int)$this->stmt("SELECT COUNT(*) FROM scanner_movimientos WHERE estado='abierto' AND vence_at<:a",['a'=>$a->format('Y-m-d H:i:s.u')])->fetchColumn();}public function lockOpenMovementForUpdate(int$id):?ScannerMovement{return$this->one("SELECT * FROM scanner_movimientos WHERE scanner_id=:id AND estado='abierto'".$this->forUpdate(),['id'=>$id]);}}
